class Solution:
  def solve(self):
    n = self.readInt()
    board = self.readMatrix(n)
    count = 0
    uniqueCount = 0
    self.helper(board, 0, n, count, uniqueCount)
    return uniqueCount

  def helper(self, board, row, n, count, uniqueCount):
    if row == n:
      uniqueCount += 1
    else:
      for col in range(n):
        if self.isValid(board, row, col, n):
          board[row][col] = 1
          self.helper(board, row + 1, n, count, uniqueCount)
          board[row][col] = 0

      def isValid(self, board, row, col, n):
        for i in range(row):
          if board[i][col] == 1 or board[row][(col - i + n) % n] == 1 or board[(row - i + n) % n][col] == 1:
            return False
        return True

  def readInt(self):
    return int(input())

  def readMatrix(self, n):
    return [list(map(int, input().split())) for _ in range(n)]
